def token_case(s, exceptions=['URL', 'ID']):
    tokens = [t.strip() for t in s.split('_') if t.strip()]
    camel_case_parts = []
    for token in tokens:
        if token.upper() in exceptions:
            camel_case_parts.append(token)
        elif camel_case_parts:
            camel_case_parts.append(token.capitalize())
        else:
            camel_case_parts.append(token.lower())
    return ''.join(camel_case_parts)
